# List all PIM assignment types for a scope — eligible AND active
$scope = '/subscriptions/00000000-0000-0000-0000-000000000000'
$token = (Get-AzAccessToken).Token
$headers = @{ Authorization = "Bearer $token" }

# 1. Eligible assignments (NOT visible via Get-AzRoleAssignment)
$eligible = Invoke-RestMethod -Method GET -Headers $headers \
    -Uri "https://management.azure.com$scope/providers/Microsoft.Authorization/roleEligibilityScheduleInstances?api-version=2020-10-01"
$eligible.value | Select-Object @{
    n='Principal'; e={$_.properties.principalId}
},@{
    n='Role'; e={$_.properties.expandedProperties.roleDefinition.displayName}
},@{
    n='EndDateTime'; e={$_.properties.endDateTime}
}

# 2. Active time-bounded PIM assignments
$active = Invoke-RestMethod -Method GET -Headers $headers \
    -Uri "https://management.azure.com$scope/providers/Microsoft.Authorization/roleAssignmentScheduleInstances?api-version=2020-10-01"
$active.value | Where-Object { $_.properties.assignmentType -eq 'Activated' } |
    Select-Object @{
        n='Principal'; e={$_.properties.principalId}
    },@{
        n='Role'; e={$_.properties.expandedProperties.roleDefinition.displayName}
    },@{
        n='EndDateTime'; e={$_.properties.endDateTime}
    }

# 3. Standard permanent assignments (non-PIM) — via normal RBAC API
Get-AzRoleAssignment -Scope $scope | Where-Object {
    $_.RoleAssignmentId -notlike '*/roleAssignmentScheduleInstances/*'
}

# Report: all currently active PIM activations across all subscriptions
# Run this to answer 'who has elevated access right now?'
$subs  = Get-AzSubscription
$token = (Get-AzAccessToken).Token
$headers = @{ Authorization = "Bearer $token" }

$allActive = foreach ($sub in $subs) {
    $scope = "/subscriptions/$($sub.Id)"
    $res = Invoke-RestMethod -Method GET -Headers $headers \
        -Uri "https://management.azure.com$scope/providers/Microsoft.Authorization/roleAssignmentScheduleInstances?api-version=2020-10-01&`$filter=assignmentType eq 'Activated'" \
        -ErrorAction SilentlyContinue
    $res.value | ForEach-Object {
        [PSCustomObject]@{
            Subscription = $sub.Name
            Principal    = $_.properties.expandedProperties.principal.displayName
            Role         = $_.properties.expandedProperties.roleDefinition.displayName
            EndDateTime  = $_.properties.endDateTime
        }
    }
}

$allActive | Sort-Object EndDateTime | Format-Table -AutoSize
